#include<bits/stdc++.h>
using namespace std;
int a[100010];
int n,m;
vector<int> mp[1000010],mp1[100010];
int in[100010];
int cnt=0;
bool flag[1000010];
stack<int> s;
vector<vector<int>> ans;
int dfn[1000010],f[1000010],low[1000010],scccnt,scc[1000010],siz[1000010],val[1000010],dfncnt;
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    s.push(x);
    if(mp[x].empty())
    {
        vector<int> now;
        now.push_back(x);
        ans.push_back(now);
        return;
    }
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
            if(dfn[x]<=low[v])
            {
                int top;
                vector<int> now;
                now.push_back(x);
                do
                {
                    top=s.top();
                    s.pop();
                    now.push_back(top);
                }while(top!=v);
                ans.push_back(now);
            }
        }
        else
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        if(u==v)
        {
            continue;
        }
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    printf("%d\n",ans.size());
    for(auto i:ans)
    {
        printf("%d ",i.size());
        for(int j:i)
        {
            printf("%d ",j);
        }
        printf("\n");
    }
    return 0;
}
